        key = (s1[0], -s1[1], la_best, la_dop, -abs(nx - (w // 2)) - abs(ny - (h // 2)), dx, dy)
        if best is None or key < best:
            best = key
            best_move = [dx, dy]

    return [int(best_move[0]), int(best_move[1])]
